mapper.select:
select * from bus_schedule_template

    
        and schedule_name like concat('%', #{query.scheduleName}, '%')
    
    
        and status = #{query.status}
    
    
        AND DATE(depart_time) >= #{query.departTime}
    
    
    
        AND DATE(depart_time) <= #{query.arriveTime}
    
    and create_user = #{userId}

ORDER BY create_time DESC
